from pathlib import Pathimport pandas as pdimport yamlDATABASE_FILE = Path(    "../src/criresviz/database/crires_settings.yaml")"""Convert the normalized CRIRES+ settings table into the YAML databaseused by CRIRESViz."""def build_database(df):    """    Build the CRIRESViz settings database from a normalized table.    Parameters    ----------    df : pandas.DataFrame        Tidy table containing the detector wavelength limits for all        CRIRES+ settings.    Returns    -------    dict        Nested dictionary ready to be written as the CRIRESViz YAML        database.    """    database = {}    for setting, group in df.groupby("setting"):        entry = {            "band": setting[0],            "reference_wavelength": float(                group["reference_wavelength"]                .iloc[0]            )/1000,            "orders": {}        }        for _, row in group.iterrows():            order = int(row["order"])            entry["orders"][order] = {                "detector1": {                    "min": float(row["detector1_min"])/1000,                    "max": float(row["detector1_max"])/1000,                },                "detector2": {                    "min": float(row["detector2_min"])/1000,                    "max": float(row["detector2_max"])/1000,                },                "detector3": {                    "min": float(row["detector3_min"])/1000,                    "max": float(row["detector3_max"])/1000,                },            }        database[setting] = entry    return databasedef write_database(database):    """    Save the CRIRESViz settings database as a YAML file.        Parameters    ----------    database : dict        Database produced by ``build_database()``.    """    with open(DATABASE_FILE, "w") as f:        yaml.safe_dump(            database,            f,            sort_keys=False,            indent=2,        )          # main                def main():    """    Generate the CRIRESViz settings database from the normalized CSV table.    """    df = pd.read_csv(        "../resources/extracted/previews/criressettings_tidy.csv"    )    database = build_database(df)        write_database(database)    print(f"Created database with {len(database)} settings")if __name__ == "__main__":    main()